1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	export type Damage = { itemType: string; amount: number };
3	export type QuoteStep = { op: "quote"; items: Item[] };
4	export type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Damage[] } };
5	export type Step = QuoteStep | ClaimStep;
6	export type Result = { premium: number } | { payout: number };
7	
8	const DEDUCTIBLE = 100;
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_RATE = 0.1;
12	const CURSE_RATE = 0.5;
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const HIGH_ENCHANTMENT_RATE = 0.3;
15	
16	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
26	
27	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
28	const COMPONENT_BLOCK_SIZE = 3;
29	const COMPONENT_BLOCK_PRICE = 60;
30	const COMPONENT_UNIT_PRICE = 25;
31	
32	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
33	
34	const roundPremium = (amount: number): number => Math.ceil(amount);
35	
36	const priceForComponentCount = (count: number): number =>
37	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : count * COMPONENT_UNIT_PRICE;
38	
39	const sumComponentBase = (componentCountsByType: Map<string, number>): number => {
40	  let total = 0;
41	  for (const count of componentCountsByType.values()) {
42	    total += priceForComponentCount(count);
43	  }
44	  return total;
45	};
46	
47	const baseForItems = (items: Item[]): number => {
48	  const componentCountsByType = new Map<string, number>();
49	  let nonComponentBase = 0;
50	  for (const item of items) {
51	    if (isComponent(item)) {
52	      componentCountsByType.set(item.type, (componentCountsByType.get(item.type) ?? 0) + 1);
53	    } else {
54	      nonComponentBase += basePremiumFor(item);
55	    }
56	  }
57	  return nonComponentBase + sumComponentBase(componentCountsByType);
58	};
59	
60	const curseSurchargeFor = (item: Item): number =>
61	  item.cursed ? basePremiumFor(item) * CURSE_RATE : 0;
62	
63	const highEnchantmentSurchargeFor = (item: Item): number =>
64	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
65	    ? basePremiumFor(item) * HIGH_ENCHANTMENT_RATE
66	    : 0;
67	
68	const PER_ITEM_MODIFIERS: ReadonlyArray<(item: Item) => number> = [
69	  curseSurchargeFor,
70	  highEnchantmentSurchargeFor,
71	];
72	
73	const modifiersForItem = (item: Item): number =>
74	  PER_ITEM_MODIFIERS.reduce((sum, modifier) => sum + modifier(item), 0);
75	
76	const itemModifiersFor = (items: Item[]): number =>
77	  items.reduce((sum, item) => sum + modifiersForItem(item), 0);
78	
79	const LOYALTY_YEARS_THRESHOLD = 2;
80	const LOYALTY_DISCOUNT_RATE = 0.2;
81	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
82	
83	type PolicyContext = { yearsWithMHPCO: number; isFollowUp: boolean };
84	type PolicyModifier = (base: number, context: PolicyContext) => number;
85	
86	const firstInsuranceSurcharge: PolicyModifier = (base) => base * FIRST_INSURANCE_RATE;
87	
88	const loyaltyDiscount: PolicyModifier = (base, { yearsWithMHPCO }) =>
89	  yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -base * LOYALTY_DISCOUNT_RATE : 0;
90	
91	const followUpDiscount: PolicyModifier = (base, { isFollowUp }) =>
92	  isFollowUp ? -base * FOLLOW_UP_DISCOUNT_RATE : 0;
93	
94	const POLICY_MODIFIERS: ReadonlyArray<PolicyModifier> = [
95	  firstInsuranceSurcharge,
96	  loyaltyDiscount,
97	  followUpDiscount,
98	];
99	
100	const policyAdjustmentFor = (base: number, context: PolicyContext): number =>
101	  POLICY_MODIFIERS.reduce((sum, modifier) => sum + modifier(base, context), 0);
102	
103	const quotePremium = (items: Item[], context: PolicyContext): number => {
104	  const base = baseForItems(items);
105	  return roundPremium(base + itemModifiersFor(items) + policyAdjustmentFor(base, context) + PROCESSING_FEE);
106	};
107	
108	const FULL_REIMBURSEMENT_RATE = 1;
109	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
110	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
111	
112	const isHighEnchantmentForClaim = (item: Item): boolean =>
113	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
114	
115	const reimbursementRateFor = (item: Item | undefined): number =>
116	  item !== undefined && isHighEnchantmentForClaim(item)
117	    ? HIGH_ENCHANTMENT_CLAIM_RATE
118	    : FULL_REIMBURSEMENT_RATE;
119	
120	const payoutForDamage = (damage: Damage, item: Item | undefined): number =>
121	  Math.floor(damage.amount * reimbursementRateFor(item) - DEDUCTIBLE);
122	
123	const findItemByType = (items: Item[], itemType: string): Item | undefined =>
124	  items.find((item) => item.type === itemType);
125	
126	const computePayout = (claim: ClaimStep, policyItems: Item[]): number =>
127	  claim.incident.damages.reduce(
128	    (sum, damage) => sum + payoutForDamage(damage, findItemByType(policyItems, damage.itemType)),
129	    0,
130	  );
131	
132	type ScenarioState = {
133	  readonly yearsWithMHPCO: number;
134	  readonly policyItemsByIndex: Map<number, Item[]>;
135	  quoteCount: number;
136	};
137	
138	const handleQuote = (step: QuoteStep, index: number, state: ScenarioState): Result => {
139	  for (const item of step.items) {
140	    if (!(item.type in BASE_PREMIUM_BY_TYPE)) {
141	      throw new Error(`Unknown item type: ${item.type}`);
